#include <bits/stdc++.h>
using namespace std;
int n,l[1000006],r[1000006],ans=0;
int dfs(int x){
    int sum=0;
    if(l[x])
        sum=dfs(l[x])+1;
    if(r[x])
        sum=max(sum,dfs(r[x])+1);
    return sum;
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&l[i],&r[i]);
    printf("%d",dfs(1)+1);
    return 0;
}
